-- =============================================================================
-- Auto Business — Planet Prediction (Graha-in-Bhava / placement)
-- Migration 005: seed graha_bhava_phal with planet-in-house Positive/Negative.
-- Source: Planet_in_12_Houses.docx (user-provided). 9 planets x 12 houses = 108.
-- -----------------------------------------------------------------------------
-- Self-contained & idempotent:
--   * creates graha_bhava_phal if absent (with positive_text/negative_text),
--   * else adds the two columns to the existing table (only if missing),
--   * then upserts all 108 rows (Hindi).
-- Import once to activate:
--   mysql -u USER -p auto_business < migrations/005_graha_bhava_phal_seed.sql
-- or phpMyAdmin -> Import.
-- =============================================================================

SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS graha_bhava_phal (
    id                  BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    planet              ENUM('Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn','Rahu','Ketu') NOT NULL,
    placed_house        TINYINT UNSIGNED NOT NULL,
    language            VARCHAR(16)      NOT NULL DEFAULT 'hi',
    positive_text       TEXT             NULL,
    negative_text       TEXT             NULL,
    prediction_text     TEXT             NULL,
    updated_by_staff_id BIGINT UNSIGNED  NULL,
    updated_at          TIMESTAMP        NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uq_graha_bhava_phal (planet, placed_house, language)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Add positive_text / negative_text to a pre-existing 004 table (portable,
-- works on MySQL and MariaDB; runs the ALTER only when the column is missing).
SET @add_pos := (SELECT COUNT(*) FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'graha_bhava_phal' AND COLUMN_NAME = 'positive_text');
SET @sql := IF(@add_pos = 0,
    'ALTER TABLE graha_bhava_phal ADD COLUMN positive_text TEXT NULL AFTER language', 'DO 0');
PREPARE s FROM @sql; EXECUTE s; DEALLOCATE PREPARE s;

SET @add_neg := (SELECT COUNT(*) FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'graha_bhava_phal' AND COLUMN_NAME = 'negative_text');
SET @sql := IF(@add_neg = 0,
    'ALTER TABLE graha_bhava_phal ADD COLUMN negative_text TEXT NULL AFTER positive_text', 'DO 0');
PREPARE s FROM @sql; EXECUTE s; DEALLOCATE PREPARE s;

INSERT INTO graha_bhava_phal (planet, placed_house, language, positive_text, negative_text) VALUES
('Sun',1,'hi',
 'प्रथम भाव में शुभ सूर्य जातक को उत्तम स्वास्थ्य, राजयोग और सरकारी कार्यों में अपार सफलता दिलाता है। ऐसा व्यक्ति मान-सम्मान प्राप्त करता है और जीवन में हमेशा एक राजा के समान यशस्वी जीवन जीता है।',
 'यदि सूर्य अशुभ हो, तो व्यक्ति को शारीरिक कष्ट का सामना करना पड़ता है और अहंकार के कारण उसके बने-बनाए काम बिगड़ जाते हैं। वैवाहिक जीवन में परेशानियां आती हैं और सरकारी महकमों से अकारण दंड या भारी विवाद की स्थिति बन सकती है।'),
('Sun',2,'hi',
 'द्वितीय भाव का शुभ सूर्य जातक को अपनी स्वयं की कड़ी मेहनत से अपार धन-दौलत और समृद्धि प्रदान करता है। व्यक्ति का परिवार सुखी रहता है और समाज में उसकी वाणी का गहरा व बहुत सकारात्मक प्रभाव पड़ता है।',
 'यदि सूर्य अशुभ हो और व्यक्ति मुफ्त की चीजों या दान के चक्कर में पड़े, तो उसका संचित धन पूरी तरह नष्ट हो जाता है। परिवार में बेवजह के झगड़े होते हैं और पैतृक संपत्ति से संबंधित मामलों में उसे भारी आर्थिक नुकसान उठाना पड़ता है।'),
('Sun',3,'hi',
 'तृतीय भाव का शुभ सूर्य जातक को अत्यंत पराक्रमी, साहसी और समाज में एक दौलतमंद इंसान के रूप में स्थापित करता है। व्यक्ति अपने बाहुबल से हर क्षेत्र में विजय प्राप्त करता है और उसे अपने भाई-बहनों का पूर्ण सहयोग मिलता है।',
 'अशुभ सूर्य होने पर यदि व्यक्ति का चाल-चलन बिगड़ने लगे, तो उसका सारा कमाया हुआ धन तेजी से बर्बाद हो जाता है। पड़ोसियों या भाई-बहनों के साथ शत्रुता बढ़ती है और व्यक्ति का असीम साहस गलत और अनैतिक कार्यों में नष्ट हो जाता है।'),
('Sun',4,'hi',
 'चतुर्थ भाव में शुभ सूर्य जातक को उत्तम आमदनी, शानदार वाहन और माता व पैतृक संपत्ति का पूर्ण सुख प्रदान करता है। व्यक्ति का घरेलू जीवन बहुत आरामदायक होता है और उसे समाज में एक अत्यंत प्रतिष्ठित इंसान की पहचान मिलती है।',
 'अशुभ सूर्य होने पर व्यक्ति का अत्यधिक क्रोध उसकी अपनी गृहस्थी और पारिवारिक सुख-शांति को पूरी तरह जलाकर राख कर देता है। माता के स्वास्थ्य में लगातार गिरावट आती है और पैतृक संपत्ति को लेकर घर में गहरे व लंबे विवाद खड़े हो जाते हैं।'),
('Sun',5,'hi',
 'पंचम भाव का शुभ सूर्य जातक को उत्तम व आज्ञाकारी संतान का सुख और उच्च कोटि की तीक्ष्ण बुद्धि प्रदान करता है। व्यक्ति अपने ज्ञान के दम पर जीवन में निरंतर प्रगति करता है और हर कदम पर अत्यधिक भाग्यशाली साबित होता है।',
 'अशुभ सूर्य के प्रभाव में यदि व्यक्ति झूठ और फरेब का सहारा लेता है, तो उसकी संतान को भारी शारीरिक व मानसिक कष्ट झेलना पड़ता है। शिक्षा में बार-बार रुकावटें आती हैं और जातक की अपनी ही गलत बुद्धि के कारण उसका मान-सम्मान मिट्टी में मिल जाता है।'),
('Sun',6,'hi',
 'छठे भाव में शुभ सूर्य जातक को अजेय शत्रुहंता बनाता है, जिससे कोई भी विरोधी या दुश्मन उसके सामने टिक नहीं पाता। व्यक्ति को ननिहाल पक्ष से उत्तम लाभ मिलता है और वह कानूनी मामलों व कोर्ट-कचहरी में हमेशा विजयी रहता है।',
 'अशुभ सूर्य के प्रभाव से जातक की पत्नी या घर की अन्य स्त्रियों के स्वास्थ्य में गंभीर व कष्टकारी समस्याएं उत्पन्न होने लगती हैं। व्यक्ति का अनावश्यक गुस्सा उसके मित्रों को भी शत्रु बना देता है और जीवन में मानसिक तनाव व कर्ज का बोझ बढ़ने लगता है।'),
('Sun',7,'hi',
 'सप्तम भाव में शुभ सूर्य जातक को एक ईमानदार जीवनसाथी देता है और वह अपने कड़े अनुशासन से जीवन में सफल होता है। व्यक्ति का चरित्र अगर पूरी तरह साफ़ रहे, तो वह अपने व्यापार और सामाजिक संपर्कों से बहुत अच्छा मान-सम्मान कमाता है।',
 'नीच स्थिति का अशुभ सूर्य जातक के वैवाहिक जीवन में भारी कलह और उसके व्यापार में भयंकर नुकसान करवाता है। व्यक्ति के चरित्र में थोड़ी सी भी खराबी उसकी पूरी सामाजिक प्रतिष्ठा और सुखी गृहस्थी को हमेशा के लिए बर्बाद कर देती है।'),
('Sun',8,'hi',
 'अष्टम भाव में यदि सूर्य शुभ हो, तो व्यक्ति रहस्यमयी विद्याओं और शोध के गहरे कार्यों में अद्वितीय सफलता प्राप्त करता है। उसे अचानक गुप्त धन की प्राप्ति होती है और विपरीत परिस्थितियों से तुरंत बाहर निकलने की अद्भुत मानसिक क्षमता मिलती है।',
 'अष्टम भाव का अशुभ सूर्य एक ''जलती आग'' के समान है, जो जातक को गंभीर स्वास्थ्य कष्ट और जीवन भर अज्ञात भय देता है। दक्षिण मुखी मकान में रहने से दुर्घटनाओं का खतरा बढ़ जाता है और गुप्त शत्रु हमेशा नुकसान पहुंचाने की फिराक में रहते हैं।'),
('Sun',9,'hi',
 'नवम भाव का शुभ सूर्य जातक को अत्यधिक भाग्यशाली, धार्मिक विचारों वाला और पैतृक संपत्ति का सच्चा वारिस बनाता है। व्यक्ति के जीवन में पिता और बुजुर्गों का पूरा आशीर्वाद रहता है, जिससे उसके हर बड़े कार्य बिना किसी बाधा के पूरे होते हैं।',
 'अशुभ सूर्य होने पर यदि व्यक्ति किसी से मुफ्त का माल या खैरात लेता है, तो उसका पूरा भाग्य रातों-रात अंधकार में डूब जाता है। पिता के साथ गहरे वैचारिक मतभेद उत्पन्न हो जाते हैं और जातक अपने ही गलत निर्णयों से अपनी अच्छी किस्मत बिगाड़ लेता है।'),
('Sun',10,'hi',
 'दशम भाव में शुभ सूर्य जातक को सरकारी क्षेत्र या अपने कर्मक्षेत्र में सर्वोच्च पद, भरपूर इज्जत और बेशुमार दौलत दिलाता है। व्यक्ति का स्वास्थ्य अत्यंत उत्तम रहता है और वह अपनी विशेष योग्यता के बल पर समाज में एक शक्तिशाली लीडर बनता है।',
 'अशुभ सूर्य होने पर व्यक्ति का अकारण दूसरों पर शक करने का वहमी स्वभाव उसके बने-बनाए करियर को तबाह कर देता है। कार्यस्थल पर झूठे आरोप लगने का भय रहता है और पिता के सुख या स्वास्थ्य में अचानक भारी कमी देखने को मिलती है।'),
('Sun',11,'hi',
 'एकादश भाव का शुभ सूर्य जातक के जीवन में आय के निरंतर नए स्रोत खोलता है और उसे समाज के अत्यंत प्रतिष्ठित लोगों से जोड़ता है। व्यक्ति की हर बड़ी मनोकामना आसानी से पूरी होती है और वह अपने परिवार के साथ एक समृद्ध तथा सुखी जीवन व्यतीत करता है।',
 'यदि सूर्य अशुभ हो और जातक मांस-मदिरा का सेवन करे, तो उसके लाभ के बने-बनाए सभी मार्ग तुरंत बंद हो जाते हैं। अचानक भारी आर्थिक नुकसान का सामना करना पड़ता है और गलत संगत के कारण समाज में व्यक्ति की घोर बदनामी होती है।'),
('Sun',12,'hi',
 'द्वादश भाव का शुभ सूर्य व्यक्ति को रात की मीठी नींद, आध्यात्मिक शांति और सुख-सुविधाओं से पूर्ण जीवन प्रदान करता है। भले ही जीवन में खर्च अधिक हों, लेकिन व्यक्ति के पास कभी धन की कमी नहीं होती और उसे विदेशों से भी उत्तम लाभ मिलता है।',
 'अशुभ सूर्य होने पर जातक दूसरों के विवादों (पराई आग) में बेवजह उलझकर अपना भारी आर्थिक और मानसिक नुकसान करवा बैठता है। रातों की नींद उड़ जाती है, व्यर्थ के मुकदमों में पैसा बर्बाद होता है और जीवन में एकांत या अस्पताल जैसी दुखद स्थिति बन सकती है।'),
('Moon',1,'hi',
 'प्रथम भाव में शुभ चंद्रमा जातक को बरगद के पेड़ के समान विशाल और आश्रय देने वाला बनाता है। व्यक्ति को अपनी माता का पूर्ण सुख और एक स्वस्थ व लंबी आयु की प्राप्ति होती है।',
 'अशुभ चंद्रमा होने पर जातक को अत्यधिक मानसिक तनाव और निर्णय लेने में भारी असमंजस का सामना करना पड़ता है। माता के स्वास्थ्य में अचानक गिरावट आती है और धन का संचय करने में मुश्किलें पैदा होती हैं।'),
('Moon',2,'hi',
 'द्वितीय भाव का शुभ चंद्रमा शिव की जटाओं से बहने वाले गंगा जल के समान अत्यंत पवित्र और अपार धन देने वाला होता है। व्यक्ति के पास कभी नकद धन (Liquid Cash) की कमी नहीं होती और माता का पूर्ण आशीर्वाद मिलता है।',
 'अशुभ चंद्रमा व्यक्ति की संचित संपत्ति और बैंक बैलेंस को अचानक बीमारियों या विवादों में नष्ट कर देता है। परिवार में शांति का अभाव रहता है और माता के साथ वैचारिक या शारीरिक दूरी बन सकती है।'),
('Moon',3,'hi',
 'तृतीय भाव में शुभ चंद्रमा जातक को अत्यंत साहसी, पराक्रमी और एक लंबी आयु का वरदान देता है। व्यक्ति अपने आत्मविश्वास और हिम्मत के बल पर जीवन में अपार सफलता और नकद धन अर्जित करता है।',
 'अशुभ चंद्रमा जातक के भीतर अज्ञात भय पैदा करता है, जिससे वह सही समय पर सही निर्णय नहीं ले पाता। भाइयों के साथ संबंधों में कड़वाहट आती है और व्यक्ति का संचित धन धीरे-धीरे खत्म होने लगता है।'),
('Moon',4,'hi',
 'चतुर्थ भाव (स्वराशि) का शुभ चंद्रमा एक बहते दरिया के समान है, जो जातक को उत्तम आमदनी और असीम मानसिक शांति देता है। व्यक्ति को माता का भरपूर प्रेम, सुख-सुविधाएं और एक बेहद आरामदायक घरेलू जीवन मिलता है।',
 'अशुभ चंद्रमा घर की सुख-शांति को पूरी तरह भंग कर देता है और माता के स्वास्थ्य को गंभीर नुकसान पहुंचाता है। आमदनी के स्रोत सूखने लगते हैं और जातक को अपने ही घर में घुटन व भयंकर मानसिक क्लेश का अनुभव होता है।'),
('Moon',5,'hi',
 'पंचम भाव का शुभ चंद्रमा एक ''रूहानी नहर'' की तरह काम करता है, जो जातक को उच्च कोटि की शिक्षा और बेहतरीन संतान सुख देता है। व्यक्ति का स्वभाव परोपकारी होता है और वह अपनी कुशाग्र बुद्धि से जीवन में खूब तरक्की करता है।',
 'अशुभ चंद्रमा के प्रभाव से जातक की शिक्षा में बार-बार बाधाएं आती हैं और संतान की तरफ से भारी कष्ट या चिंता मिलती है। जातक यदि अपने गुप्त राज दूसरों को बता दे, तो उसकी बनी-बनाई योजनाएं पूरी तरह विफल हो जाती हैं।'),
('Moon',6,'hi',
 'छठे भाव में यदि चंद्रमा शुभ प्रभाव में हो तो जातक अपने शत्रुओं पर आसानी से विजय प्राप्त करता है और विपरीत परिस्थितियों में भी मानसिक संतुलन बनाए रखता है। व्यक्ति को अपने ननिहाल पक्ष से विशेष सहयोग और आर्थिक लाभ प्राप्त होता है।',
 'अशुभ चंद्रमा ''पाताल का पानी'' बन जाता है, जो जातक को भयंकर मानसिक तनाव और गहरे अवसाद (Depression) में धकेल देता है। माता के स्वास्थ्य को भारी कष्ट होता है और व्यक्ति बिना वजह के कर्ज या मुकदमों में बुरी तरह फंस जाता है।'),
('Moon',7,'hi',
 'सप्तम भाव का शुभ चंद्रमा व्यक्ति को व्यापार में भारी मुनाफा और साक्षात ''लक्ष्मी'' के समान गुणवान पत्नी का सुख देता है। जातक का वैवाहिक जीवन अत्यंत सुखद होता है और वह समाज में एक शांत व सफल व्यक्ति के रूप में जाना जाता है।',
 'अशुभ चंद्रमा होने पर जातक के घर में माता और पत्नी के बीच भयंकर क्लेश (सास-बहू का झगड़ा) हमेशा बना रहता है। वैवाहिक जीवन की शांति छिन जाती है और साझेदारी वाले व्यापार में जातक को भारी आर्थिक नुकसान उठाना पड़ता है।'),
('Moon',8,'hi',
 'अष्टम भाव में यदि चंद्रमा शुभ स्थिति में हो, तो व्यक्ति रहस्यमयी और गुप्त विद्याओं का बहुत गहरा जानकार बनता है। जातक को अचानक से पैतृक संपत्ति या गुप्त धन का लाभ मिलता है और वह मानसिक रूप से अत्यंत मजबूत होता है।',
 'अष्टम भाव का अशुभ चंद्रमा ''श्मशान के पानी'' के समान बेहद घातक होता है, जो जातक को गंभीर डिप्रेशन और अज्ञात भय का शिकार बना देता है। माता के जीवन पर भारी संकट मंडराता है और जातक को स्वास्थ्य संबंधी गंभीर समस्याएं उत्पन्न होती हैं।'),
('Moon',9,'hi',
 'नवम भाव का शुभ चंद्रमा जातक को जन्म से ही अत्यधिक भाग्यशाली और धर्म-कर्म के प्रति गहरी आस्था रखने वाला बनाता है। व्यक्ति अपने अच्छे कर्मों और ईश्वर की कृपा से जीवन में अपार सुख, धन और समाज में उच्च पद प्राप्त करता है।',
 'अशुभ चंद्रमा जातक के भाग्य को पूरी तरह रोक देता है और उसे धर्म के मार्ग से भटकाकर मानसिक अशांति देता है। माता-पिता के सुख में भारी कमी आती है और व्यक्ति को जीवन भर कड़ा संघर्ष और दरिद्रता का सामना करना पड़ता है।'),
('Moon',10,'hi',
 'दशम भाव का शुभ चंद्रमा जातक को अपने कार्यक्षेत्र में अपार सफलता, मान-सम्मान और एक स्थिर करियर प्रदान करता है। व्यक्ति अपने पेशे में अत्यधिक निपुण होता है और उसकी छवि समाज में एक बहुत ही परोपकारी इंसान की होती है।',
 'अशुभ चंद्रमा जातक को ''रात का अंधा'' बना देता है, जिससे उसे छाती व कफ की गंभीर बीमारियां घेर लेती हैं। कर्मक्षेत्र और धन की स्थिति में भारी उतार-चढ़ाव आते हैं, जिससे जीवन में कभी स्थिरता नहीं आ पाती।'),
('Moon',11,'hi',
 'एकादश भाव का शुभ चंद्रमा जातक के जीवन में धन-दौलत और आय के निरंतर बढ़ने वाले कई नए मार्ग खोलता है। व्यक्ति की सभी बड़ी इच्छाएं पूरी होती हैं और वह भौतिक सुखों के साथ-साथ एक गहरा आध्यात्मिक स्वभाव भी रखता है।',
 'अशुभ चंद्रमा के प्रभाव से जातक की आमदनी के रास्ते अचानक बंद हो जाते हैं और वह दिमागी रूप से बेहद परेशान रहने लगता है। परिवार की स्त्रियों को कष्ट होता है और बिना वजह का सांसारिक अकेलापन या निराशा व्यक्ति को घेर लेती है।'),
('Moon',12,'hi',
 'द्वादश भाव का शुभ चंद्रमा ''बारिश के पानी'' के समान है, जो जातक को रातों की अत्यंत सुखद और मीठी नींद प्रदान करता है। व्यक्ति के खर्चे अच्छे और शुभ कार्यों में होते हैं, जिससे उसे बाहरी स्थानों या विदेश से भी उत्तम लाभ मिलता है।',
 'अशुभ चंद्रमा जातक की रातों की नींद पूरी तरह उड़ा देता है और उसके भीतर बेवजह का क्रोध व मानसिक अशांति भर देता है। आमदनी से कई गुना अधिक बेतहाशा खर्चे होने लगते हैं, जो जातक को भारी आर्थिक संकट में डाल देते हैं।'),
('Mars',1,'hi',
 'प्रथम भाव में शुभ मंगल जातक को अत्यंत साहसी, दबंग और न्यायप्रिय स्वभाव का बनाता है। व्यक्ति को सरकारी दरबार और उच्च पदों से भारी आर्थिक लाभ व अपार सफलता प्राप्त होती है।',
 'अशुभ मंगल व्यक्ति को अत्यधिक क्रोधी और अहंकारी बना देता है, जिससे उसके कई दुश्मन पैदा हो जाते हैं। झूठ बोलने और अनैतिक कार्य करने से उसकी किस्मत और शारीरिक स्वास्थ्य दोनों खराब हो जाते हैं।'),
('Mars',2,'hi',
 'द्वितीय भाव का शुभ मंगल जातक को अपार पैतृक संपत्ति और ससुराल पक्ष से विशेष आर्थिक लाभ दिलाता है। व्यक्ति अपने पूरे परिवार का रक्षक होता है और अपने साहस से व्यापार में खूब धन कमाता है।',
 'अशुभ मंगल जातक की संचित संपत्ति को भाइयों या रिश्तेदारों के साथ होने वाले विवादों में नष्ट कर देता है। पारिवारिक जीवन में कड़वाहट आती है और बड़े भाई के साथ संबंध पूरी तरह बिगड़ कर शत्रुता में बदल जाते हैं।'),
('Mars',3,'hi',
 'तृतीय भाव का शुभ मंगल जातक को शेर के समान निडर बनाता है और वह अपने असीम पराक्रम से विजय पाता है। व्यक्ति को अपने सगे भाई-बहनों का पूरा सुख मिलता है और हर कदम पर उनका मजबूत सहयोग प्राप्त होता है।',
 'अशुभ मंगल व्यक्ति को घमंडी और हिंसक बना देता है, जिससे उसका सारा पराक्रम गलत कार्यों में बर्बाद होता है। चरित्र खराब होने से जातक का धन, मान-सम्मान और भाइयों का साथ जीवन भर के लिए छूट जाता है।'),
('Mars',4,'hi',
 'चतुर्थ भाव में शुभ मंगल जातक को अचल संपत्ति, भूमि और उत्तम मकान का पूर्ण सुख प्रदान करता है। व्यक्ति के भीतर गजब की सकारात्मक ऊर्जा होती है जिसका उपयोग वह अपने परिवार की भलाई और सुरक्षा के लिए करता है।',
 'चतुर्थ भाव का अशुभ मंगल ''मंगल बद'' या पानी में आग के समान है, जो घर की सुख-शांति को पूरी तरह जला देता है। जातक की माता के स्वास्थ्य को भारी कष्ट होता है और घरेलू जीवन में हमेशा भयंकर क्लेश व विवाद बना रहता है।'),
('Mars',5,'hi',
 'पंचम भाव का शुभ मंगल जातक को उत्तम, संस्कारी और हमेशा आज्ञा मानने वाली संतान का सुख प्रदान करता है। व्यक्ति शिक्षा के क्षेत्र में बहुत भाग्यशाली होता है और अपनी कुशाग्र बुद्धि से जीवन में खूब तरक्की करता है।',
 'अशुभ मंगल जातक की संतान के जीवन और स्वास्थ्य में बार-बार भारी कष्ट तथा बड़ी रुकावटें पैदा करता है। व्यक्ति का स्वभाव चिड़चिड़ा हो जाता है और उसके गलत व जल्दबाजी में लिए गए फैसलों से शिक्षा व धन का नुकसान होता है।'),
('Mars',6,'hi',
 'छठे भाव में शुभ मंगल जातक को एक अजेय शत्रुहंता बनाता है, जिससे दुश्मन उसके सामने कभी टिक नहीं पाते। व्यक्ति अपने अदम्य साहस से कर्ज और बीमारियों को मात देकर कोर्ट-कचहरी व मुकदमों में हमेशा विजयी रहता है।',
 'अशुभ मंगल जातक को बिना वजह अपने ही सगे रिश्तेदारों और भाइयों का कट्टर दुश्मन बना देता है। बेवजह के विवादों और लंबे मुकदमों में धन की भारी बर्बादी होती है तथा शारीरिक कष्ट लगातार बना रहता है।'),
('Mars',7,'hi',
 'सप्तम भाव का शुभ मंगल जातक को एक मजबूत और कर्मठ जीवनसाथी दिलाता है, जो हर सुख-दुख में ढाल बनकर खड़ा रहता है। व्यक्ति को अपने व्यापार और साझेदारी वाले कामों में बहुत अच्छा मुनाफा और निरंतर सफलता मिलती है।',
 'अशुभ मंगल एक भयंकर मांगलिक दोष बनाता है, जो जीवनसाथी के स्वास्थ्य को भारी कष्ट और गंभीर बीमारियां देता है। वैवाहिक जीवन में हमेशा क्लेश रहता है और व्यापारिक साझेदारियों में जातक को बड़ा धोखा व नुकसान झेलना पड़ता है।'),
('Mars',8,'hi',
 'अष्टम भाव में शुभ मंगल व्यक्ति को विपरीत और अचानक आने वाली संकटपूर्ण स्थितियों से सुरक्षित निकाल लेता है। जातक को अचानक अचल संपत्ति या गुप्त धन का लाभ मिलता है और वह शारीरिक व मानसिक रूप से काफी मजबूत होता है।',
 'अष्टम भाव का अशुभ मंगल ''मौत का फंदा'' कहलाता है, जो व्यक्ति को भयानक दुर्घटनाओं और रक्त संबंधी बीमारियों का शिकार बनाता है। जातक को हमेशा अचानक आने वाली मृत्यु, सर्जरी या किसी बड़े शारीरिक नुकसान का गहरा भय सताता रहता है।'),
('Mars',9,'hi',
 'नवम भाव का शुभ मंगल जातक को जीवन में एक शक्तिशाली राजयोग और अत्यंत भाग्यशाली जीवन प्रदान करता है। व्यक्ति धर्म के मार्ग पर चलता है और उसे अपने बुजुर्गों का पूरा आशीर्वाद, मान-सम्मान व पैतृक संपत्ति प्राप्त होती है।',
 'अशुभ मंगल व्यक्ति को नास्तिक और बड़ों का अपमान करने वाला बना देता है, जिससे उसका पूरा भाग्य रुक जाता है। किस्मत का साथ न मिलने से जातक को हर काम में असफलता, निराशा और जीवन में कड़े संघर्ष का सामना करना पड़ता है।'),
('Mars',10,'hi',
 'दशम भाव का शुभ और उच्च का मंगल जातक को अपार अचल संपत्ति, बेतहाशा दौलत और शानदार राजयोग दिलाता है। व्यक्ति अपने कर्मक्षेत्र में अत्यंत प्रतिष्ठित होता है और उसे समाज या सरकारी क्षेत्र में एक शक्तिशाली पद मिलता है।',
 'अशुभ मंगल के प्रभाव से जातक अपनी गलतियों और जल्दबाजी के कारण अपनी सारी पैतृक संपत्ति बेचकर बर्बाद कर देता है। कार्यस्थल पर उसे भारी अपमान झेलना पड़ता है और लगातार असफलताओं के कारण उसका करियर पूरी तरह ठप हो जाता है।'),
('Mars',11,'hi',
 'एकादश भाव का शुभ मंगल जातक को अत्यधिक साहसी बनाता है और जीवन में आमदनी के निरंतर नए स्रोत खोलता है। व्यक्ति भौतिक सुखों के साथ-साथ आध्यात्मिक विचारों वाला होता है और उसे अपने मित्रों से भारी आर्थिक सहयोग मिलता है।',
 'अशुभ मंगल होने पर जातक यदि बुरे व्यसनों में पड़ जाए, तो उसके लाभ और आय के सभी रास्ते तुरंत बंद हो जाते हैं। गलत संगत और अनैतिक कार्यों के कारण धन की भारी हानि होती है और विश्वासपात्र दोस्त भी अचानक दुश्मन बन जाते हैं।'),
('Mars',12,'hi',
 'द्वादश भाव में शुभ मंगल जातक की बाहरी दुश्मनों और जीवन के छिपे हुए बड़े खतरों से हमेशा रक्षा करता है। व्यक्ति का पैसा शुभ कार्यों में खर्च होता है, जिससे उसे विदेशों से या जन्मस्थान से दूर उत्तम मान-सम्मान और लाभ मिलता है।',
 'अशुभ मंगल जातक को अत्यंत क्रोधी और हिंसक बना देता है, जिससे उसे हमेशा दुर्घटनाओं या हथियारों से गहरा खतरा बना रहता है। व्यक्ति का सारा कमाया हुआ पैसा कोर्ट-कचहरी, अस्पताल और व्यर्थ के विवादों में पानी की तरह बर्बाद हो जाता है।'),
('Mercury',1,'hi',
 'प्रथम भाव में शुभ बुध जातक को राजा के समान तीक्ष्ण बुद्धि और व्यापारिक चातुर्य प्रदान करता है। व्यक्ति अपनी होशियारी से हर काम में सफलता पाता है और समाज में अत्यंत सम्मानित होता है।',
 'अशुभ बुध व्यक्ति के दिमाग को बुरे व्यसनों और बेईमानी की तरफ भटका देता है। दिमागी तनाव बना रहता है और गलत फैसलों के कारण व्यापार व सेहत (विशेषकर नसों) में भारी नुकसान होता है।'),
('Mercury',2,'hi',
 'द्वितीय भाव का शुभ बुध जातक को अत्यंत मीठी और प्रभावशाली वाणी देता है, जिससे वह अपार दौलत कमाता है। व्यक्ति अपने पिता का बहुत बड़ा मददगार साबित होता है और सुखी पारिवारिक जीवन जीता है।',
 'अशुभ बुध व्यक्ति की ज़ुबान को कड़वा बना देता है, जिससे बने-बनाए काम और रिश्ते बिगड़ जाते हैं। पिता की संपत्ति का नाश होता है और तोते या पक्षी पालने से आर्थिक संकट गहरा सकता है।'),
('Mercury',3,'hi',
 'तृतीय भाव में बुध शुभ हो तो व्यक्ति अपनी तार्किक क्षमता और चतुराई से विपरीत परिस्थितियों पर विजय पाता है। भाई-बहनों के सहयोग से उसे व्यापारिक और व्यक्तिगत जीवन में भारी लाभ मिलता है।',
 'अशुभ (मंदा) बुध व्यक्ति को दमे की बीमारी या सांस की गंभीर तकलीफें दे सकता है। भाइयों और रिश्तेदारों से गहरे मतभेद हो जाते हैं और व्यक्ति अपनी ही चालाकी में फंसकर बर्बाद होता है।'),
('Mercury',4,'hi',
 'चतुर्थ भाव का शुभ बुध जातक को श्रेष्ठ बुद्धि और एक मजबूत राजयोग प्रदान करता है। व्यक्ति को माता का पूर्ण सुख, अच्छी आमदनी और एक बेहद सुखी पारिवारिक जीवन मिलता है।',
 'अशुभ बुध माता के स्वास्थ्य को भारी नुकसान पहुंचाता है और घर की सुख-शांति को मानसिक तनाव में बदल देता है। अपने नाम पर व्यापार करने से व्यक्ति को अचानक बड़ा आर्थिक घाटा सहना पड़ता है।'),
('Mercury',5,'hi',
 'पंचम भाव का शुभ बुध व्यक्ति की वाणी में ''आकाशवाणी'' जैसी शक्ति देता है, यानी वह जो बोलता है सच हो जाता है। जातक को उच्च शिक्षा और श्रेष्ठ व होनहार संतान का अपार सुख प्राप्त होता है।',
 'अशुभ बुध व्यक्ति की बुद्धि को भ्रष्ट कर देता है और संतान के स्वास्थ्य या तरक्की में भारी रुकावटें डालता है। गले में ताबीज़ आदि पहनने से परेशानियां और बढ़ जाती हैं तथा मानसिक बेचैनी लगातार रहती है।'),
('Mercury',6,'hi',
 'छठे भाव में उच्च का शुभ बुध जातक को रहस्यमयी और कूटनीतिक बुद्धि देता है जिससे वह दुश्मनों पर हावी रहता है। व्यापार और नौकरी में जातक को अपनी वाक्पटुता के बल पर असाधारण सफलता मिलती है।',
 'अशुभ बुध जातक की वाणी को जहरीला बना देता है; यदि वह किसी को बददुआ दे तो अपना ही भारी नुकसान कर बैठता है। व्यक्ति को दांतों और नसों की भयंकर बीमारियों का सामना करना पड़ता है।'),
('Mercury',7,'hi',
 'सप्तम भाव का शुभ बुध जातक को एक सफल ''कलम का धनी'' और अत्यंत चालाक व्यापारी बनाता है। व्यक्ति को उत्तम आय प्राप्त होती है और जीवनसाथी के भाग्य से उसके व्यापार में बेतहाशा वृद्धि होती है।',
 'अशुभ बुध व्यक्ति के वैवाहिक जीवन में कड़वाहट और व्यापार में भयंकर नुकसान करवाता है। यदि जातक अपनी बहन-बेटी को रुलाता है, तो उसकी आमदनी के सारे रास्ते तुरंत ठप हो जाते हैं।'),
('Mercury',8,'hi',
 'अष्टम भाव का शुभ बुध व्यक्ति को रहस्यमयी विद्याओं और शोध कार्यों में बहुत गहरा ज्ञान देता है। जातक अपनी गुप्त और तीक्ष्ण बुद्धि से किसी भी बड़ी मुश्किल से आसानी से बाहर निकल आता है।',
 'अष्टम भाव का अशुभ बुध ''श्मशान का तोता'' है, जो जातक को गंभीर दिमागी उलझन और अज्ञात भय में रखता है। नसों और दांतों में भारी कष्ट होता है और अचानक आने वाली दिमागी बीमारियां घेर लेती हैं।'),
('Mercury',9,'hi',
 'नवम भाव का शुभ बुध जातक को धार्मिक विचारों के साथ-साथ अत्यंत कुशाग्र और तार्किक बुद्धि देता है। व्यक्ति अपने ज्ञान के दम पर अपना भाग्य चमकाता है और उसे बुजुर्गों का आशीर्वाद मिलता है।',
 'अशुभ बुध व्यक्ति का भाग्य रोक देता है और उसे हर समय मानसिक बेचैनी व तनाव का शिकार बनाए रखता है। पिता के स्वास्थ्य व धन को कष्ट होता है और व्यक्ति बुरी संगत में पड़कर अपना पतन कर लेता है।'),
('Mercury',10,'hi',
 'दशम भाव का शुभ बुध जातक को बेहतरीन कूटनीतिज्ञ (जी-हजूरिया) और व्यापार में माहिर बनाता है। व्यक्ति को राजदरबार (सरकारी क्षेत्र) और उच्च अधिकारियों से भारी आर्थिक व सामाजिक लाभ मिलता है।',
 'अशुभ बुध व्यक्ति के करियर को अस्थिर कर देता है और कूटनीति की जगह उसे एक धोखेबाज़ इंसान बना देता है। शराब या मांस का सेवन करने से जातक का मान-सम्मान और व्यापार पूरी तरह नष्ट हो जाता है।'),
('Mercury',11,'hi',
 'एकादश भाव का शुभ बुध जातक को अपने मित्रों और संपर्कों के माध्यम से भारी आर्थिक लाभ दिलाता है। विशेषकर 34 वर्ष की आयु के बाद व्यक्ति बेशुमार दौलत और अपार सफलता प्राप्त करता है।',
 'अशुभ बुध व्यक्ति को व्यर्थ की चिंताओं और खयाली पुलाव में उलझाए रखता है, जिससे आय के मार्ग बंद हो जाते हैं। दोस्तों से धोखा मिलता है और व्यक्ति अपनी ही गलतियों से अपनी आमदनी को नुकसान पहुंचाता है।'),
('Mercury',12,'hi',
 'द्वादश भाव का शुभ बुध व्यक्ति को शांत स्वभाव और आध्यात्मिक विषयों में गहरी सूझबूझ प्रदान करता है। जातक अपने खर्चों पर समझदारी से नियंत्रण रखता है और विदेशों या जन्मस्थान से दूर लाभ कमाता है।',
 'नीच का अशुभ बुध व्यक्ति की रातों की नींद पूरी तरह खराब कर देता है और उसे दिमागी रूप से परेशान रखता है। जातक खयाली पुलाव पकाता रहता है और व्यर्थ के क्रोध से अपना सारा धन और सेहत बर्बाद कर लेता है।'),
('Jupiter',1,'hi',
 'प्रथम भाव में शुभ गुरु जातक को राजा के समान अत्यंत ज्ञानी, उच्च शिक्षित और गद्दी का मालिक बनाता है। व्यक्ति को अपने ज्ञान और शराफत के बल पर समाज में सर्वोच्च मान-सम्मान प्राप्त होता है।',
 'अशुभ गुरु होने पर व्यक्ति अहंकार में आकर अपना मान-सम्मान खो बैठता है और शिक्षा में बाधाएं आती हैं। मुफ्त का माल या खैरात लेने से उसका अपना भाग्य और बरकत पूरी तरह से नष्ट हो जाती है।'),
('Jupiter',2,'hi',
 'द्वितीय भाव का शुभ गुरु जातक को अपार धन-संपत्ति, प्रभावशाली वाणी और बेहतरीन पैतृक सुख प्रदान करता है। व्यक्ति अपने परिवार का पालन-पोषण बहुत अच्छी तरह करता है और समाज में उसकी बात का गहरा असर होता है।',
 'अशुभ गुरु के प्रभाव से जातक की संचित संपत्ति और बैंक बैलेंस तेजी से नष्ट होने लगता है। घर आए मेहमान का अपमान करने या कटु वाणी बोलने से पारिवारिक सुख-शांति छिन जाती है।'),
('Jupiter',3,'hi',
 'तृतीय भाव का शुभ गुरु जातक को शेर के समान असीम साहसी बनाता है और वह अपने पराक्रम से अपार धन कमाता है। व्यक्ति अपनी मेहनत के बल पर जीवन में खूब तरक्की करता है और हमेशा बड़ों का सम्मान करता है।',
 'अशुभ गुरु होने पर जातक को अपने मित्रों और सगे भाइयों से कोई विशेष लाभ या सहयोग नहीं मिल पाता। व्यक्ति यदि बड़ों का अपमान करे, तो उसका साहस और भाग्य दोनों हमेशा के लिए उसका साथ छोड़ देते हैं।'),
('Jupiter',4,'hi',
 'चतुर्थ भाव में उच्च का शुभ गुरु जातक के लिए एक शक्तिशाली राजयोग बनाता है, जो उत्तम घर और असीम ज्ञान देता है। व्यक्ति ज्ञान का अथाह सागर होता है और उसे अपनी माता व परिवार से पूर्ण सहयोग व सुख मिलता है।',
 'अशुभ गुरु घर की सुख-शांति को भंग कर देता है और जातक को घरेलू जीवन में भयंकर मानसिक तनाव झेलना पड़ता है। नंगे बदन रहने या खराब आचरण से जातक की माता को भारी शारीरिक कष्ट और जातक को धन की हानि होती है।'),
('Jupiter',5,'hi',
 'पंचम भाव का शुभ गुरु जातक को कुशाग्र बुद्धि, उत्तम शिक्षा और श्रेष्ठ व आज्ञाकारी संतान का सुख प्रदान करता है। व्यक्ति को जीवन में अचानक धन लाभ होता है और वह अपने ज्ञान व भाग्य से जीवन में निरंतर प्रगति करता है।',
 'अशुभ गुरु के प्रभाव से जातक की संतान को भारी शारीरिक या मानसिक कष्ट झेलना पड़ता है। व्यक्ति के नास्तिक बनने या दूसरों से दान मांगने पर उसकी किस्मत पूरी तरह रुक जाती है और विद्या का नाश होता है।'),
('Jupiter',6,'hi',
 'छठे भाव में शुभ गुरु जातक को साधू के समान परोपकारी स्वभाव देता है और विपरीत परिस्थितियों में भी रक्षा करता है। व्यक्ति अपनी समझदारी से शत्रुओं पर हावी रहता है और धर्म-कर्म से जुड़े रहकर जीवन में सफलता पाता है।',
 'अशुभ गुरु जातक को कफ, दमा या सांस लेने में भारी दिक्कत जैसी गंभीर स्वास्थ्य समस्याएं देता है। मुफ्त की चीजें लेने या खैरात स्वीकार करने से व्यक्ति भारी कर्ज में डूब जाता है और उसकी सारी बरकत खत्म हो जाती है।'),
('Jupiter',7,'hi',
 'सप्तम भाव का शुभ गुरु व्यक्ति को वैरागी या सन्यासी स्वभाव का बनाता है, लेकिन धन-दौलत के मामले में अपार सफलता देता है। जातक का वैवाहिक जीवन शांतिपूर्ण रहता है और व्यापार में उसे अपनी ईमानदारी का बहुत अच्छा व लाभकारी फल मिलता है।',
 'अशुभ गुरु जातक की गृहस्थी में अकारण कलह पैदा करता है और जीवनसाथी के स्वास्थ्य पर बहुत बुरा असर डालता है। घर में मूर्तियां रखने या दिखावा करने से व्यक्ति को व्यापारिक साझेदारियों में भारी नुकसान और धोखा मिलता है।'),
('Jupiter',8,'hi',
 'अष्टम भाव का शुभ गुरु ''श्मशान के साधू'' के समान है, जो जातक को लंबी आयु और गुप्त विद्याओं का गहरा ज्ञान देता है। व्यक्ति रहस्यमयी विषयों में महारत हासिल करता है और अचानक आने वाले किसी भी बड़े संकट से सुरक्षित रहता है।',
 'अशुभ गुरु जातक को श्वास संबंधी भयंकर रोग देता है और अचानक किसी बड़ी दुर्घटना या अज्ञात भय का डर बना रहता है। गले में ताबीज या गंडा पहनने से स्वास्थ्य में भारी गिरावट आती है और गुप्त शत्रु भारी नुकसान पहुंचाते हैं।'),
('Jupiter',9,'hi',
 'नवम भाव का शुभ गुरु जातक को जन्म से ही भाग्यशाली, पक्के मकान का मालिक और धर्म-कर्म में विश्वास रखने वाला बनाता है। व्यक्ति को जीवन भर अपने बुजुर्गों का पूरा सुख व आशीर्वाद मिलता है और उसकी किस्मत हर मोड़ पर साथ देती है।',
 'अशुभ गुरु व्यक्ति के भाग्य को पूरी तरह रोक देता है और वह अपने ही गलत आचरण से अपनी किस्मत बिगाड़ लेता है। धर्म के विरुद्ध काम करने या नास्तिक विचार रखने से जातक को जीवन भर कड़ा संघर्ष और दरिद्रता का सामना करना पड़ता है।'),
('Jupiter',10,'hi',
 'दशम भाव में शुभ गुरु जातक को अपने कार्यक्षेत्र में अत्यंत सम्मानजनक स्थिति और आजीविका के उत्तम साधन प्रदान करता है। व्यक्ति अपने श्रेष्ठ कर्मों और ईमानदारी के बल पर समाज या सरकारी क्षेत्र में एक सफल और प्रतिष्ठित इंसान बनता है।',
 'नीच का अशुभ गुरु व्यक्ति को कफ, दमा और सांस की गंभीर बीमारियां देता है जिससे उसका स्वास्थ्य लगातार खराब रहता है। कर्मक्षेत्र और धन की स्थिति में भारी उतार-चढ़ाव आते हैं और जातक को अपने करियर में बेवजह की बदनामी सहनी पड़ती है।'),
('Jupiter',11,'hi',
 'एकादश भाव का शुभ गुरु जातक के पिता के लिए अत्यंत शुभ होता है और व्यक्ति को अचानक अपार धन की प्राप्ति होती है। व्यक्ति की आमदनी के स्रोत हमेशा बढ़ते रहते हैं और उसकी हर भौतिक व आध्यात्मिक मनोकामना आसानी से पूरी होती है।',
 'अशुभ गुरु होने पर जातक यदि झूठे वादे करे या बेईमानी करे, तो उसके आय के सभी मार्ग तुरंत बंद हो जाते हैं। अचानक भारी आर्थिक नुकसान का सामना करना पड़ता है और संकट के समय मित्रों या शुभचिंतकों का साथ पूरी तरह छूट जाता है।'),
('Jupiter',12,'hi',
 'द्वादश भाव का शुभ गुरु एक सच्चे रक्षक की तरह काम करता है, जो जातक को सुख की नींद और गहरी मानसिक शांति प्रदान करता है। व्यक्ति का धन हमेशा अच्छे और परोपकारी कार्यों में खर्च होता है, जिससे उसे हर जगह यश और सम्मान मिलता है।',
 'अशुभ गुरु व्यक्ति को रातों की नींद से वंचित कर देता है और व्यर्थ के मुकदमों व विवादों में धन की भारी बर्बादी करवाता है। किसी की झूठी गवाही देने या दूसरों को धोखा देने से जातक को भयंकर कानूनी अड़चनों या आर्थिक दंड का सामना करना पड़ता है।'),
('Venus',1,'hi',
 'प्रथम भाव में शुभ शुक्र जातक को अत्यंत आकर्षक व्यक्तित्व और ''मच्छ रेखा'' के प्रभाव से अपार धन-दौलत प्रदान करता है। व्यक्ति विपरीत लिंग के बीच अत्यधिक लोकप्रिय होता है और जीवन में सभी प्रकार की विलासिता का आनंद लेता है।',
 'अशुभ शुक्र होने पर जातक का चरित्र कमजोर हो जाता है, जिससे उसका सारा संचित धन और मान-सम्मान पूरी तरह नष्ट हो जाता है। स्वास्थ्य संबंधी परेशानियां घेर लेती हैं और जीवनसाथी के साथ संबंधों में भारी कड़वाहट आ जाती है।'),
('Venus',2,'hi',
 'द्वितीय भाव का शुभ शुक्र व्यक्ति को अपनी मेहनत की कमाई से अपार धन-संपत्ति और एक बेहद सुखी गृहस्थी का वरदान देता है। जातक के पास हमेशा नकदी की प्रचुरता रहती है और उसका पारिवारिक जीवन अत्यंत सुखमय और समृद्ध होता है।',
 'अशुभ शुक्र व्यक्ति के पारिवारिक जीवन में भयंकर कलह पैदा करता है और धन के संचय में भारी रुकावटें डालता है। खेती या पैतृक कार्यों में जातक को बड़ा आर्थिक घाटा सहना पड़ता है और घर की सुख-शांति छिन जाती है।'),
('Venus',3,'hi',
 'तृतीय भाव का शुभ शुक्र जातक को अत्यंत आकर्षक बनाता है, जिससे वह स्त्रियों के बीच बहुत लोकप्रिय और सम्मानित होता है। व्यक्ति को अपने पराक्रम से गुप्त धन की प्राप्ति होती है और उसका वैवाहिक जीवन अत्यंत आनंददायक रहता है।',
 'अशुभ शुक्र व्यक्ति को विपरीत लिंग के प्रति बुरी आदतों में फंसा देता है, जिससे उसकी सामाजिक प्रतिष्ठा मिट्टी में मिल जाती है। भाई-बहनों से संबंध बिगड़ जाते हैं और जातक अनैतिक कार्यों के कारण अपनी जमापूंजी बुरी तरह बर्बाद कर लेता है।'),
('Venus',4,'hi',
 'चतुर्थ भाव में शुभ शुक्र जातक को उत्तम आमदनी, शानदार वाहन और घरेलू सुख-सुविधाओं से पूर्ण जीवन प्रदान करता है। व्यक्ति का जीवन अत्यंत विलासितापूर्ण होता है और उसे समाज तथा मित्रों से भरपूर सहयोग व प्रेम मिलता है।',
 'अशुभ शुक्र घर में हमेशा माता और पत्नी के बीच भयंकर क्लेश (सास-बहू का झगड़ा) और मानसिक अशांति पैदा करता है। पारिवारिक शांति पूरी तरह नष्ट हो जाती है और व्यक्ति को घरेलू घुटन व भारी आर्थिक संकट का सामना करना पड़ता है।'),
('Venus',5,'hi',
 'पंचम भाव का शुभ शुक्र जातक को रोमांटिक स्वभाव का बनाता है और प्रेम संबंधों व विवाह में अत्यधिक सफलता दिलाता है। व्यक्ति अपनी रचनात्मक प्रतिभा से समाज में खूब नाम कमाता है और उसे विपरीत परिस्थितियों में भी अचानक धन लाभ होता है।',
 'अशुभ शुक्र व्यक्ति के प्रेम संबंधों में भारी बदनामी लाता है और संतान की ओर से उसे गंभीर शारीरिक या मानसिक कष्ट मिलता है। धन की स्थिति में लगातार उतार-चढ़ाव आते रहते हैं और व्यक्ति अपनी गलतियों व सट्टेबाजी की वजह से नुकसान उठाता है।'),
('Venus',6,'hi',
 'छठे भाव में यदि शुक्र शुभ प्रभाव में हो तो व्यक्ति विपरीत परिस्थितियों और शत्रुओं पर विजय प्राप्त करके गुप्त धन कमाता है। जातक को अपनी मेहनत और सतर्कता के बल पर जीवन में अप्रत्याशित आर्थिक सफलता और समाज में रुतबा मिलता है।',
 'छठे भाव का नीच और अशुभ शुक्र अत्यंत घातक होता है, जो जातक की पत्नी के स्वास्थ्य को भयंकर और लंबी बीमारियां देता है। व्यक्ति भारी कर्ज में बुरी तरह डूब जाता है और उसके जीवन में बिना किसी कारण के गुप्त शत्रु पैदा हो जाते हैं।'),
('Venus',7,'hi',
 'सप्तम भाव का शुभ शुक्र जातक को ''लक्ष्मी'' के समान गुणवान पत्नी और एक अत्यंत ऐश्वर्यशाली वैवाहिक जीवन का सुख देता है। व्यक्ति को साझेदारी वाले व्यापार में भारी मुनाफा होता है और समाज में उसकी प्रतिष्ठा निरंतर तेजी से बढ़ती है।',
 'अशुभ शुक्र वैवाहिक जीवन में भारी अशांति और जीवनसाथी के साथ गंभीर मतभेद या अलगाव की स्थिति पैदा कर देता है। व्यापार में भयंकर घाटा होता है और व्यक्ति की पारिवारिक सुख-सुविधाओं तथा धन का पूरी तरह से नाश हो जाता है।'),
('Venus',8,'hi',
 'अष्टम भाव का शुभ शुक्र जातक को जीवनसाथी के माध्यम से या किसी वसीयत के जरिए अचानक भारी गुप्त धन की प्राप्ति करवाता है। व्यक्ति गुप्त और रहस्यमयी विद्याओं का ज्ञाता होता है और कठिन से कठिन हालातों से सुरक्षित बाहर आ जाता है।',
 'अशुभ शुक्र जातक और उसकी पत्नी को भयंकर गुप्त रोग और गंभीर स्वास्थ्य संबंधी समस्याएं प्रदान करता है। अचानक दुर्घटनाओं और बेवजह के विवादों में व्यक्ति का सारा संचित धन पानी की तरह बहकर नष्ट हो जाता है।'),
('Venus',9,'hi',
 'नवम भाव का शुभ शुक्र जातक को अत्यंत भाग्यशाली बनाता है और विशेषकर विवाह के तुरंत बाद उसका शानदार भाग्योदय होता है। व्यक्ति को लंबी और लाभदायक यात्राओं का अवसर मिलता है तथा वह जीवन में अपार सुख और समृद्धि भोगता है।',
 'अशुभ शुक्र जातक के भाग्य के दरवाज़े बंद कर देता है, जिससे उसे हर काम में भारी मेहनत के बावजूद केवल निराशा ही हाथ लगती है। व्यक्ति का दांपत्य जीवन कष्टमय रहता है और उसे जीवन भर पैसों की तंगी व संघर्ष का सामना करना पड़ता है।'),
('Venus',10,'hi',
 'दशम भाव का शुभ शुक्र जातक को उसके कर्मक्षेत्र में बहुत अच्छी स्थिति दिलाता है और पत्नी के भाग्य से उसे अपार धन प्राप्त होता है। व्यक्ति समाज में एक रुतबेदार जीवन जीता है और उसकी कलात्मक क्षमता उसे करियर में नई ऊंचाइयां देती है।',
 'अशुभ शुक्र जातक को अत्यधिक शक्की स्वभाव का बना देता है, जिससे वह अपने ही शुभचिंतकों और जीवनसाथी से दूर हो जाता है। कार्यक्षेत्र में अस्थिरता रहती है और व्यक्ति को अपने करियर व संपत्ति के मामलों में भयंकर नुकसान सहना पड़ता है।'),
('Venus',11,'hi',
 'एकादश भाव का शुभ शुक्र जातक के जीवन में आय के निरंतर नए स्रोत खोलता है और स्त्रियों के सहयोग से उसे भारी आर्थिक लाभ होता है। व्यक्ति की हर बड़ी भौतिक मनोकामना आसानी से पूरी होती है और उसे अचानक गुप्त धन व संपत्ति की प्राप्ति होती है।',
 'अशुभ शुक्र के कारण जातक गलत संगत और बुरे व्यसनों का शिकार हो जाता है, जिससे उसकी आय के सभी रास्ते बंद हो जाते हैं। स्त्रियों से धोखा मिलता है और व्यक्ति को समाज में भारी बदनामी तथा बड़ा आर्थिक नुकसान झेलना पड़ता है।'),
('Venus',12,'hi',
 'द्वादश भाव में उच्च का शुभ शुक्र जातक को बेहिसाब दौलत, सांसारिक विलासिता और रातों का अत्यंत उत्तम शयन सुख प्रदान करता है। व्यक्ति का जीवनसाथी उसके लिए अत्यंत भाग्यशाली साबित होता है और वह एक राजा के समान ऐश्वर्यशाली जीवन जीता है।',
 'अशुभ शुक्र जातक की किस्मत को पलट कर उसे भयंकर कर्ज और दरिद्रता की ओर धकेल देता है। वैवाहिक जीवन में भारी दुख आता है, सुख-सुविधाएं छिन जाती हैं और मानसिक क्लेश के कारण व्यक्ति की रातों की नींद पूरी तरह उड़ जाती है।'),
('Saturn',1,'hi',
 'प्रथम भाव का शुभ शनि जातक को राजा के वज़ीर के समान अत्यंत अमीर और प्रतिष्ठित बनाता है। व्यक्ति अपनी चालाकी और कर्मठता से जीवन में अपार सफलता और सरकारी लाभ प्राप्त करता है।',
 'अशुभ शनि के कारण जातक के जीवन में ''काग रेखा'' (दरिद्रता) छा जाती है और लगातार असफलताएं मिलती हैं। बिना सोचे-समझे अपनी कमाई से मकान बनाने पर व्यक्ति को भयंकर आर्थिक संकट झेलना पड़ता है।'),
('Saturn',2,'hi',
 'द्वितीय भाव का शुभ शनि व्यक्ति को अपार धन, संपत्ति और पैतृक सुख का सच्चा वारिस बनाता है। जातक अपनी चालाकी और दूरदृष्टि से व्यापार में बेतहाशा मुनाफा कमाकर समृद्ध जीवन जीता है।',
 'अशुभ शनि व्यक्ति के संचित धन और बैंक बैलेंस को बुरी तरह नष्ट कर देता है। परिवार में हमेशा क्लेश रहता है और जातक कर्ज के बोझ तले दबकर दरिद्रता का जीवन जीने पर मजबूर हो जाता है।'),
('Saturn',3,'hi',
 'तृतीय भाव में शुभ शनि जातक को ''शेर की आंख'' जैसा असीम साहस और अद्भुत पराक्रम देता है। व्यक्ति को अपने पुरुषार्थ से अचानक भारी धन लाभ होता है और समाज में उसका दबदबा कायम रहता है।',
 'अशुभ शनि व्यक्ति को अत्यंत डरपोक बना देता है, जिससे वह अपने ही बने-बनाए काम बिगाड़ लेता है। भाई-बहनों से दुश्मनी हो जाती है और गलत आदतों के कारण उसका सारा धन बर्बाद हो जाता है।'),
('Saturn',4,'hi',
 'चतुर्थ भाव का शुभ शनि जातक को संपत्ति, मकान और वाहन का उत्तम सुख प्रदान करता है। व्यक्ति अपने परिवार के साथ भौतिक सुख-सुविधाओं से युक्त एक सुरक्षित और शांतिपूर्ण जीवन व्यतीत करता है।',
 'चतुर्थ भाव का नीच शनि ''जल में सांप'' के समान घातक होता है जो घर की सारी शांति डस लेता है। जातक की माता के स्वास्थ्य को भारी कष्ट होता है और घरेलू जीवन में हमेशा भयंकर क्लेश बना रहता है।'),
('Saturn',5,'hi',
 'पंचम भाव का शुभ शनि जातक को अत्यंत कुशाग्र और तकनीकी दिमाग (Technical Mind) वाला बनाता है। व्यक्ति अपनी मेहनत और विशेष बुद्धि के दम पर बहुत अच्छी शिक्षा व शानदार सफलता हासिल करता है।',
 'अशुभ शनि होने पर जातक को संतान प्राप्ति में भारी देरी या संतान की ओर से भयंकर कष्ट मिलता है। शिक्षा में बार-बार रुकावटें आती हैं और व्यक्ति अपनी गलत सोच से अपना ही नुकसान कर बैठता है।'),
('Saturn',6,'hi',
 'छठे भाव में शुभ शनि जातक को एक अजेय शत्रुहंता बनाता है, जिससे विरोधी उसके सामने कभी टिक नहीं पाते। विशेषकर 36 वर्ष की आयु के बाद व्यक्ति को अपने कार्यक्षेत्र में शानदार और अप्रत्याशित आर्थिक लाभ मिलता है।',
 'अशुभ शनि व्यक्ति को गंभीर और लंबी बीमारियों का शिकार बना देता है, जिससे स्वास्थ्य बहुत खराब रहता है। बेवजह के मुकदमों और कोर्ट-कचहरी के मामलों में जातक का बहुत पैसा और समय बर्बाद होता है।'),
('Saturn',7,'hi',
 'सप्तम भाव में उच्च का शुभ शनि व्यक्ति को एक चतुर व्यापारी और अपार धन-दौलत का स्वामी बनाता है। जातक को व्यापार और जीवनसाथी के माध्यम से असीम सफलता व भाग्य का पूरा साथ मिलता है।',
 'अशुभ शनि जातक की पत्नी या जीवनसाथी के स्वास्थ्य पर भयंकर प्रहार करता है और वैवाहिक सुख उजाड़ देता है। साझेदारी के कामों में भारी धोखा मिलता है और व्यक्ति का फलता-फूलता व्यापार पूरी तरह ठप हो जाता है।'),
('Saturn',8,'hi',
 'अष्टम भाव का शुभ शनि जातक को एक अत्यंत लंबी आयु और गहरे रहस्यों या गुप्त विद्याओं का ज्ञान देता है। व्यक्ति को जीवन में अचानक गुप्त धन या पैतृक संपत्ति का भारी लाभ मिलने के प्रबल योग बनते हैं।',
 'अष्टम भाव का अशुभ शनि ''मौत के सांप'' के समान है जो जातक को हमेशा भयंकर दुर्घटनाओं का भय देता है। स्वास्थ्य संबंधी गंभीर बीमारियां और अचानक आने वाले संकट व्यक्ति का जीवन अत्यंत कष्टकारी बना देते हैं।'),
('Saturn',9,'hi',
 'नवम भाव का शुभ शनि जातक को अत्यंत भाग्यशाली, धार्मिक और कई मकानों या संपत्तियों का मालिक बनाता है। व्यक्ति को अपने बुजुर्गों का पूरा आशीर्वाद मिलता है और वह एक अत्यंत लंबी व सुखी आयु भोगता है।',
 'अशुभ शनि व्यक्ति के भाग्य के दरवाज़े पूरी तरह बंद कर देता है, जिससे हर काम में सिर्फ असफलता हाथ लगती है। किस्मत रूठ जाने के कारण जातक को जीवन भर कड़ा संघर्ष और आर्थिक तंगी का सामना करना पड़ता है।'),
('Saturn',10,'hi',
 'दशम भाव का शुभ शनि जातक को अत्यंत कर्मठ बनाता है और पिता की संपत्ति में बेतहाशा विस्तार करवाता है। व्यक्ति अपने कर्मों के बल पर राजसी सुख, सरकार से लाभ और समाज में उच्च पद प्राप्त करता है।',
 'अशुभ शनि के प्रभाव से व्यक्ति का करियर बुरी तरह लड़खड़ा जाता है और कार्यस्थल पर उसे भारी अपमान सहना पड़ता है। पिता के स्वास्थ्य को गंभीर नुकसान होता है और व्यक्ति की सारी मेहनत बेकार चली जाती है।'),
('Saturn',11,'hi',
 'एकादश भाव का शुभ शनि जातक के लिए धन का असीम भंडार खोलता है और उसे अचानक भारी लाभ दिलाता है। व्यक्ति की सभी मनोकामनाएं पूरी होती हैं और वह अपने जीवन में अपार भौतिक सुख-सुविधाओं का आनंद लेता है।',
 'अशुभ शनि होने पर यदि व्यक्ति बुरे व्यसनों में पड़ जाए, तो उसकी आमदनी के सारे रास्ते हमेशा के लिए बंद हो जाते हैं। अचानक आने वाले आर्थिक संकटों और धोखे के कारण व्यक्ति भयंकर दरिद्रता का शिकार हो जाता है।'),
('Saturn',12,'hi',
 'द्वादश भाव का शुभ शनि जातक को गुप्त और रहस्यमयी विद्याओं का महान ज्ञाता बनाता है। व्यक्ति को सुख की मीठी नींद आती है और उसके धन का उपयोग शुभ तथा भविष्य संवारने वाले कार्यों में होता है।',
 'अशुभ शनि व्यक्ति की रातों की नींद पूरी तरह उड़ा देता है और उसे भयंकर मानसिक तनाव में रखता है। दूसरों के मामलों में बेवजह दखल देने से जातक को भारी आर्थिक नुकसान व कानूनी विवाद झेलने पड़ते हैं।'),
('Rahu',1,'hi',
 'प्रथम भाव में शुभ राहु जातक को राजा के समान अत्यंत कुशाग्र बुद्धि, तेज दिमाग और प्रभावशाली व्यक्तित्व प्रदान करता है। व्यक्ति अपनी रणनीति और सूझबूझ से हर क्षेत्र में सफलता प्राप्त करता है और जीवन में मान-सम्मान का विस्तार करता है।',
 'अशुभ राहु व्यक्ति को बेवजह की दुश्मनी और विवादों में उलझा देता है, जिससे उसका मानसिक संतुलन बिगड़ सकता है। अहंकार और गलत फैसलों के कारण जातक का पतन होता है और नीले रंग की वस्तुओं के संपर्क से उसे भारी नुकसान उठाना पड़ता है।'),
('Rahu',2,'hi',
 'द्वितीय भाव का शुभ राहु जातक के धन की रक्षा करने में मददगार साबित होता है और अचानक धन लाभ के अवसर देता है। व्यक्ति के ससुराल पक्ष से संबंध अत्यंत मधुर होते हैं, जिससे उसे समय-समय पर आर्थिक सहायता व लाभ प्राप्त होता है।',
 'अशुभ राहु व्यक्ति को धन के मामले में चोरों या धोखाधड़ी का शिकार बना देता है, जिससे उसकी आर्थिक स्थिति लड़खड़ा जाती है। ससुराल पक्ष से विवाद बढ़ जाते हैं और इलेक्ट्रॉनिक उपकरणों के उपयोग से जातक को बार-बार बड़े आर्थिक नुकसान का सामना करना पड़ता है।'),
('Rahu',3,'hi',
 'तृतीय भाव में उच्च का राहु जातक को किसी पहरेदार के समान निडर और अपनी धुन का पक्का बनाता है। व्यक्ति अपने साहस और तकनीकी कौशल से जीवन में अप्रत्याशित सफलताएं हासिल करता है और दुश्मनों के लिए काल साबित होता है।',
 'अशुभ राहु व्यक्ति के चरित्र पर दाग लगा देता है, जिससे उसकी प्रतिष्ठा और अचानक अर्जित की हुई संपत्ति क्षण भर में नष्ट हो जाती है। अवैध कार्यों में लिप्त होने से जातक का पतन निश्चित हो जाता है और वह अपने ही पराक्रम से मुसीबतें मोल ले बैठता है।'),
('Rahu',4,'hi',
 'चतुर्थ भाव में शुभ राहु जातक को राजनीति या प्रशासनिक क्षेत्र में अचानक सफलता और उच्च पद दिलाता है। व्यक्ति अपनी समझदारी का उपयोग करके घर की सुख-सुविधाओं को बढ़ाने में सफल रहता है और उसे जीवन में भौतिक सुख मिलता है।',
 'अशुभ राहु माता के स्वास्थ्य को अत्यंत गंभीर कष्ट देता है और घर के रसोईघर की ऊर्जा को पूरी तरह दूषित कर देता है। जातक को भयंकर मानसिक तनाव और अशांति का सामना करना पड़ता है, जिससे उसका घरेलू जीवन दुखद बन जाता है।'),
('Rahu',5,'hi',
 'पंचम भाव का शुभ राहु जातक को तकनीकी शिक्षा में महारत और शेयर या सट्टे के काम में बड़ी सफलता दिलाता है। व्यक्ति अपनी तीक्ष्ण बुद्धि से धन का सृजन करता है और उसे अपनी संतान की ओर से नई प्रगति के अवसर मिलते हैं।',
 'अशुभ राहु जातक को जुए और सट्टे की लत में फंसाकर उसके पूरे धन और भविष्य को बर्बाद कर देता है। पेट संबंधी गंभीर बीमारियां घेर लेती हैं और संतान के भविष्य को लेकर हमेशा अनिश्चितता व चिंता बनी रहती है।'),
('Rahu',6,'hi',
 'छठे भाव में उच्च का शुभ राहु जातक को एक सफल शत्रुहंता बनाता है, जिससे कोई भी विरोधी उसके सामने नहीं टिकता। व्यक्ति रहस्यमयी और गुप्त कार्यों में विजय प्राप्त करता है और अचानक आए हुए बड़े संकटों को भी अपनी बुद्धि से मात देता है।',
 'अशुभ राहु जातक के भाई-बहनों से संबंध खराब करवा देता है और गुप्त बीमारियां देकर उसका स्वास्थ्य बिगाड़ देता है। व्यक्ति कर्ज के बोझ में बुरी तरह दब जाता है और अपने ही गलत निर्णयों के कारण कानूनी पचड़ों में फंसकर बर्बाद होता है।'),
('Rahu',7,'hi',
 'सप्तम भाव का शुभ राहु व्यक्ति को व्यापार में अद्भुत कूटनीति और हर कठिन परिस्थिति को अपने पक्ष में मोड़ने की शक्ति देता है। जातक के सामाजिक संपर्क बहुत प्रभावशाली होते हैं और उसे विवाह के माध्यम से अचानक तरक्की के द्वार खुलते हुए दिखाई देते हैं।',
 'अशुभ राहु वैवाहिक जीवन में भयंकर उलझनें और अचानक मतभेद पैदा कर देता है, जिससे गृहस्थी बिखरने की कगार पर आ जाती है। व्यापार में जातक को बड़ी धोखाधड़ी और पार्टनरशिप में धोखे का सामना करना पड़ता है, जिससे भारी आर्थिक हानि होती है।'),
('Rahu',8,'hi',
 'अष्टम भाव का शुभ राहु जातक को अचानक आने वाले संकटों से निपटने की अद्भुत क्षमता और शोध कार्यों में सफलता देता है। व्यक्ति अपनी चतुराई से कोर्ट-कचहरी और विवादों से सुरक्षित बाहर निकल आता है और गुप्त धन पाने का अधिकारी बनता है।',
 'अष्टम भाव का नीच राहु अचानक भयंकर दुर्घटनाओं, कोर्ट-कचहरी के चक्करों और गंभीर स्वास्थ्य समस्याओं का कारण बनता है। जातक का जीवन वहम और डर से भर जाता है, जिससे वह अपनी उन्नति का कोई भी मार्ग तय नहीं कर पाता।'),
('Rahu',9,'hi',
 'नवम भाव का शुभ राहु जातक को धर्म और यात्राओं के माध्यम से अपने भाग्य को बदलने का अद्वितीय अवसर प्रदान करता है। व्यक्ति अपनी मेहनत से उन ऊंचाइयों तक पहुंचता है जहाँ तक पहुंचना दूसरों के लिए कठिन होता है, बशर्ते वह धार्मिक मार्ग पर चले।',
 'अशुभ राहु व्यक्ति को नास्तिक और धर्म के प्रति भ्रमित कर देता है, जिससे उसका पूरा भाग्य अचानक अंधकार में डूब जाता है। झूठी गवाही देने के कारण जातक के जीवन में दरिद्रता और भारी बदनामी आती है, जिससे सब कुछ नष्ट हो जाता है।'),
('Rahu',10,'hi',
 'दशम भाव का शुभ राहु जातक को मशीनरी और आधुनिक तकनीकी कार्यों में अपार सफलता और सरकारी क्षेत्र से लाभ दिलाता है। व्यक्ति अपने करियर में सिर उठाकर चलता है और अपनी मेहनत से पिता का नाम रोशन करते हुए बड़ी उपलब्धियां प्राप्त करता है।',
 'अशुभ राहु व्यक्ति के पिता के स्वास्थ्य और मान-सम्मान को गंभीर नुकसान पहुंचाता है और करियर में अस्थिरता लाता है। जातक को बार-बार अपमान सहना पड़ता है और गलत कार्यों में लिप्त होने से उसका भविष्य धुएं में खो जाता है।'),
('Rahu',11,'hi',
 'एकादश भाव का शुभ राहु जातक को छप्पर फाड़ धन और लॉटरी जैसे अचानक बड़े आर्थिक लाभ के योग प्रदान करता है। व्यक्ति की सभी भौतिक मनोकामनाएं पूरी होती हैं और वह माया के भंडार का स्वामी बनकर वैभवशाली जीवन जीता है।',
 'अशुभ राहु जातक को गलत आदतों व मांस-मदिरा के सेवन में फंसाकर उसकी सारी दौलत और सुख-सुविधाएं छीन लेता है। जातक के सारे बने-बनाए लाभ अचानक खत्म हो जाते हैं और वह घोर आर्थिक तंगी व बदनामी के दौर से गुजरता है।'),
('Rahu',12,'hi',
 'द्वादश भाव का शुभ राहु व्यक्ति को अपनी कल्पना शक्ति से बड़ी सफलता दिलाने और ख्याली पुलाव को हकीकत में बदलने की शक्ति देता है। जातक अपने खर्चों का प्रबंधन समझदारी से करता है और गुप्त कार्यों के माध्यम से धन का सृजन करने में सफल होता है।',
 'अशुभ राहु जातक की रातों की नींद पूरी तरह उड़ा देता है और उसे खयाली दुनिया में खोकर समय बर्बाद करने पर मजबूर करता है। बेतहाशा और अनियंत्रित खर्चों के कारण व्यक्ति भारी आर्थिक संकट में फंस जाता है और उसे अपार मानसिक अशांति झेलनी पड़ती है।'),
('Ketu',1,'hi',
 'प्रथम भाव में शुभ केतु जातक को वैराग्य की गहरी समझ और लंबी यात्राओं से जीवन में असीम सफलता दिलाता है। व्यक्ति का स्वभाव अत्यंत सरल और परोपकारी होता है, जिससे वह लोगों के बीच आदर का पात्र बनता है।',
 'अशुभ केतु व्यक्ति को अत्यधिक घुमक्कड़ और अस्थिर बना देता है, जिससे उसका ध्यान किसी भी एक लक्ष्य पर नहीं टिकता। अकारण विवादों में फंसने और बंदरों या आवारा जानवरों से जुड़ी परेशानियों के कारण जातक को जीवन में भारी मानसिक तनाव मिलता है।'),
('Ketu',2,'hi',
 'द्वितीय भाव का शुभ केतु जातक को अपनी बातों में जादूई प्रभाव और यात्राओं के माध्यम से धन अर्जित करने की शक्ति देता है। व्यक्ति की वाणी इतनी प्रभावशाली होती है कि लोग उसकी बातों से बहुत जल्दी प्रभावित हो जाते हैं और उसे हर कार्य में लाभ मिलता है।',
 'अशुभ केतु व्यक्ति की आर्थिक स्थिति में भारी उतार-चढ़ाव लाता है और उसके द्वारा दी गई जुबान अक्सर उलटी पड़ जाती है। धन का संचय करने में बार-बार अड़चनें आती हैं और व्यक्ति अपनी गलतियों की वजह से अपनी जमापूंजी खो बैठता है।'),
('Ketu',3,'hi',
 'तृतीय भाव में शुभ केतु जातक को बहुत साहसी और धनवान बनाता है, जिससे उसे अपने भाई-बहनों का भरपूर प्यार व सहयोग मिलता है। व्यक्ति अपने पराक्रम के बल पर समाज में बहुत ऊँचा नाम कमाता है और उसे सुख-सुविधाओं की कभी कमी नहीं होती।',
 'अशुभ केतु व्यक्ति को शारीरिक रूप से कमजोर बना देता है और कान या रीढ़ की हड्डी से संबंधित कष्ट देता है। भाई-बहनों के साथ मतभेद उभर आते हैं और जातक का साहस खो जाने से वह कठिन परिस्थितियों में घबराकर पीछे हट जाता है।'),
('Ketu',4,'hi',
 'चतुर्थ भाव का शुभ केतु जातक को शांतिपूर्ण घरेलू जीवन और अचानक प्राप्त होने वाली सुखद स्थितियों का अनुभव कराता है। व्यक्ति अपने परिवार के प्रति अत्यंत समर्पित होता है और उसे जीवन के हर मोड़ पर आंतरिक संतुष्टि प्राप्त होती है।',
 'अशुभ केतु ''पानी में कुत्ता'' बनकर घर की सारी सुख-शांति छीन लेता है और माता के स्वास्थ्य को अत्यंत गंभीर कष्ट देता है। संतान के भविष्य को लेकर भारी चिंता बनी रहती है और घर में हमेशा अनचाही परेशानियां व अशांति का माहौल रहता है।'),
('Ketu',5,'hi',
 'पंचम भाव का शुभ केतु जातक को अत्यंत तीक्ष्ण छठी इंद्री (Intuition) और अपनी योजनाओं में अद्भुत सफलता प्रदान करता है। व्यक्ति को श्रेष्ठ संतान का सुख मिलता है और वह अपनी गुप्त रणनीतियों से जीवन में बहुत तरक्की करता है।',
 'अशुभ केतु व्यक्ति की संतान को शारीरिक कष्ट देता है और शिक्षा या धन के मामलों में बड़ी रुकावटें पैदा करता है। जातक अपनी योजनाओं को गुप्त न रख पाने के कारण असफल हो जाता है और पेट संबंधी बीमारियों का शिकार बनता है।'),
('Ketu',6,'hi',
 'छठे भाव में उच्च का शुभ केतु जातक को एक अजेय शत्रुहंता बनाता है, जिससे कोई भी विरोधी उसे नुकसान नहीं पहुँचा सकता। व्यक्ति अपनी मेहनत और गुप्त बुद्धि से अचानक धन के बड़े लाभ प्राप्त करता है और कर्ज व बीमारियों को पूरी तरह मिटा देता है।',
 'अशुभ केतु व्यक्ति को गुप्त बीमारियों और नसों के खिंचाव से जूझने पर मजबूर करता है, जिससे उसका स्वास्थ्य हमेशा खराब रहता है। अकारण मुकदमों में फंसने और कर्ज का बोझ बढ़ने से जातक की सारी सुख-शांति छिन जाती है और वह बदहाल हो जाता है।'),
('Ketu',7,'hi',
 'सप्तम भाव का शुभ केतु जातक को अपने वादे का पक्का और व्यापार में बहुत ईमानदार व्यक्ति बनाता है। व्यक्ति को वैवाहिक जीवन में शांति और साझेदारी के कार्यों में अपनी निष्ठा के कारण अच्छा मान-सम्मान प्राप्त होता है।',
 'अशुभ केतु वैवाहिक जीवन में अनावश्यक तनाव और गलतफहमियां पैदा करता है, जिससे संबंधों में कड़वाहट बढ़ जाती है। झूठे वादे करने से व्यापार में जातक की प्रतिष्ठा गिरती है और अहंकारी स्वभाव के कारण उसे भारी नुकसान उठाना पड़ता है।'),
('Ketu',8,'hi',
 'अष्टम भाव में शुभ केतु व्यक्ति को लंबी आयु प्रदान करता है और उसे जीवन की बड़ी दुर्घटनाओं से सुरक्षित बचा लेता है। जातक को अपनी सूझबूझ से गुप्त धन के अवसर मिलते हैं और वह शरीर के जोड़ों के दर्द या यूरिन इन्फेक्शन से मुक्त रहता है।',
 'अष्टम भाव का नीच केतु ''मौत का फंदा'' है जो अचानक दुर्घटनाओं, गंभीर शारीरिक कष्टों और पैरों की बीमारियों को जन्म देता है। जीवन में बार-बार होने वाले बड़े नुकसान और यूरिन संबंधी गंभीर समस्याएं जातक के लिए बहुत कष्टकारी सिद्ध होती हैं।'),
('Ketu',9,'hi',
 'नवम भाव का शुभ केतु जातक को जन्म से ही भाग्यशाली, पिता का आज्ञाकारी और धर्म के मार्ग पर चलने वाला बनाता है। व्यक्ति अपने अच्छे कर्मों के कारण जीवन में बहुत ऊँचाई प्राप्त करता है और उसे हर कार्य में ईश्वर की विशेष कृपा मिलती है।',
 'अशुभ केतु व्यक्ति के भाग्य को पूरी तरह रोक देता है, जिससे उसे हर प्रयास में असफलता व निराशा हाथ लगती है। पिता के सुख में भारी कमी आती है और जातक का मन भटकने के कारण वह जीवन में सही राह नहीं चुन पाता।'),
('Ketu',10,'hi',
 'दशम भाव का शुभ केतु जातक के चरित्र को बहुत ऊंचा बनाता है और उसे अपने कार्यक्षेत्र में अपार सफलता व इज्जत दिलाता है। व्यक्ति अपनी मेहनत से जीवन में बहुत ऊँचा मुकाम हासिल करता है और भाग्य का उसे हर कदम पर साथ मिलता है।',
 'अशुभ केतु व्यक्ति को अत्यधिक शक्की और चरित्रहीन बनाने की कोशिश करता है, जिससे समाज में उसकी घोर बदनामी होती है। भाग्य का साथ न मिलने और कर्मक्षेत्र में बार-बार असफलताओं के कारण जातक का आर्थिक व सामाजिक जीवन बर्बाद हो जाता है।'),
('Ketu',11,'hi',
 'एकादश भाव का शुभ केतु जातक को भविष्यवक्ता की तरह दूरदर्शी बनाता है और उसे अपार धन व राजयोग दिलाता है। व्यक्ति की आर्थिक स्थिति अत्यंत सुदृढ़ होती है और वह अपने विवेक से भविष्य की सभी योजनाएं सफल बनाता है।',
 'अशुभ केतु व्यक्ति की आमदनी के सारे रास्ते बंद कर देता है और उसे गलत संगति या नशों की लत में धकेल देता है। आर्थिक तंगी और भविष्य को लेकर भारी अनिश्चितता के कारण जातक को जीवन में बहुत बड़े संकटों का सामना करना पड़ता है।'),
('Ketu',12,'hi',
 'द्वादश भाव में उच्च का शुभ केतु जातक को असीम रूहानियत, शांति और रातों की उत्तम नींद प्रदान करता है। व्यक्ति मोक्ष की ओर अग्रसर होता है और उसे अपने जीवन के खर्चों में भी सकारात्मक परिणाम व गहरी आत्मिक संतुष्टि मिलती है।',
 'अशुभ केतु व्यक्ति की मानसिक शांति को पूरी तरह छीन लेता है, जिससे उसे रातों को गहरी अशांति और डर महसूस होता है। व्यर्थ के खर्चों और अनियंत्रित जीवनशैली के कारण जातक भारी कर्ज व मानसिक अवसाद की चपेट में आ जाता है।')
